snippets.C0642:
-- Caso: Promedio (clásico) | Nivel: Básico | Categoría: Clásicos | ID: C0642
CREATE OR REPLACE FUNCTION solve_c0642(p_arr bigint[])
RETURNS double precision
LANGUAGE plpgsql
AS $$
DECLARE
  s bigint := 0;
  n integer := COALESCE(array_length(p_arr,1),0);
  i integer := 0;
BEGIN
  IF n = 0 THEN
    RETURN NULL;
  END IF;

  WHILE i < n LOOP
    s := s + p_arr[i+1];
    i := i + 1;
  END LOOP;

  RETURN (s::double precision) / n;
END;
$$;

CREATE OR REPLACE PROCEDURE sp_solve_c0642(p_arr bigint[], INOUT p_out double precision)
LANGUAGE plpgsql
AS $$
BEGIN
  p_out := solve_c0642(p_arr);
END;
$$;

