snippets.C0644:
-- Caso: Búsqueda binaria (clásico) | Nivel: Intermedio | Categoría: Clásicos | ID: C0644
CREATE OR REPLACE FUNCTION solve_c0644(p_arr bigint[], p_target bigint)
RETURNS integer
LANGUAGE plpgsql
AS $$
DECLARE
  lo integer := 0;
  hi integer := COALESCE(array_length(p_arr, 1), 0) - 1;
  mid integer;
  v bigint;
BEGIN
  WHILE lo <= hi LOOP
    mid := (lo + hi) / 2;
    v := p_arr[mid+1]; -- PostgreSQL arrays son 1-based
    IF v = p_target THEN
      RETURN mid;
    ELSIF v < p_target THEN
      lo := mid + 1;
    ELSE
      hi := mid - 1;
    END IF;
  END LOOP;
  RETURN -1;
END;
$$;

CREATE OR REPLACE PROCEDURE sp_solve_c0644(p_arr bigint[], p_target bigint, INOUT p_out integer)
LANGUAGE plpgsql
AS $$
BEGIN
  p_out := solve_c0644(p_arr, p_target);
END;
$$;

