snippets.C0646:
-- Caso: Validar RUT chileno | Nivel: Intermedio | Categoría: Validación | ID: C0646
CREATE OR REPLACE FUNCTION validate_rut(p_rut text)
RETURNS boolean
LANGUAGE plpgsql
AS $$
DECLARE
  clean text := upper(regexp_replace(p_rut, '[\.\-\s]', '', 'g'));
  body text;
  dv text;
  sumv int := 0;
  mul int := 2;
  i int;
  d int;
  modv int;
  dv_calc text;
BEGIN
  IF length(clean) < 2 THEN RETURN false; END IF;

  body := left(clean, length(clean)-1);
  dv := right(clean, 1);

  IF body !~ '^[0-9]+$' THEN RETURN false; END IF;

  FOR i IN REVERSE 1..length(body) LOOP
    d := substring(body from i for 1)::int;
    sumv := sumv + d * mul;
    mul := CASE WHEN mul = 7 THEN 2 ELSE mul + 1 END;
  END LOOP;

  modv := 11 - (sumv % 11);
  dv_calc := CASE WHEN modv = 11 THEN '0'
                  WHEN modv = 10 THEN 'K'
                  ELSE modv::text END;

  RETURN dv = dv_calc;
END;
$$;

-- Demo
SELECT validate_rut('12.345.678-5') AS is_valid;

